var surah028 = {
  number: 28,
  nameArabic: "Al-Qasas",
  nameEnglish: "Al-Qasas",
  meaning: "The Stories",
  totalAyahs: 88,
  ayahs: [
    { number: 1, arabic: "طسٓمٓ", transliteration: "Taseenmeem", transliterationB: "Taa-Seeen-Meeem", english: "Ta. Sin. Mim", romanUrdu: "Taa seen Meem" },
    { number: 2, arabic: "تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْمُبِينِ", transliteration: "Tilka ayatu alkitabi almubeeni", transliterationB: "Tilka Aayaatul Kitaabil mubeen", english: "These are Verses of the Book that makes (things) clear", romanUrdu: "Yeh kitaab e mubeen(clear book) ki aayat hain" },
    { number: 3, arabic: "نَتْلُوا۟ عَلَيْكَ مِن نَّبَإِ مُوسَىٰ وَفِرْعَوْنَ بِٱلْحَقِّ لِقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Natloo AAalayka min nabai moosa wafirAAawna bialhaqqi liqawmin yuminoona", transliterationB: "Natloo 'alaika min naba-i Moosaa wa Fi'awna bilhaqqi liqawminy yu'miinoon", english: "We rehearse to thee some of the story of Moses and Pharaoh in Truth, for people who believe", romanUrdu: "Hum Moosa aur Firoun ka kuch haal theek theek tumhein sunate hain aisey logon ke faiyde ke liye jo iman layein" },
    { number: 4, arabic: "إِنَّ فِرْعَوْنَ عَلَا فِى ٱلْأَرْضِ وَجَعَلَ أَهْلَهَا شِيَعًۭا يَسْتَضْعِفُ طَآئِفَةًۭ مِّنْهُمْ يُذَبِّحُ أَبْنَآءَهُمْ وَيَسْتَحْىِۦ نِسَآءَهُمْ ۚ إِنَّهُۥ كَانَ مِنَ ٱلْمُفْسِدِينَ", transliteration: "Inna firAAawna AAala fee alardi wajaAAala ahlaha shiyaAAan yastadAAifu taifatan minhum yuthabbihu abnaahum wayastahyee nisaahum innahu kana mina almufsideena", transliterationB: "Inna Fir'awna 'alaa fil ardi wa ja'ala ahlahaa shiya'ai yastad'ifu taaa'ifatam minhum yuzabbihu abnaaa'ahum wa yastahyee nisaaa'ahum; innahoo kaana minal mufsideen", english: "Truly Pharaoh elated himself in the land and broke up its people into sections, depressing a small group among them: their sons he slew, but he kept alive their females: for he was indeed a maker of mischief", romanUrdu: "Waqia yeh hai ke Firoun ne zameen mein sarkashi ki aur uske bashindon ko girohon mein taseem kardiya, un mein se ek giroh ko woh zaleel karta tha, iske ladkon ko qatal karta aur uski ladkiyon ko jeeta (zinda) rehne deta tha. Fil waqai woh mufsid (mischief-makers) logon mein se tha" },
    { number: 5, arabic: "وَنُرِيدُ أَن نَّمُنَّ عَلَى ٱلَّذِينَ ٱسْتُضْعِفُوا۟ فِى ٱلْأَرْضِ وَنَجْعَلَهُمْ أَئِمَّةًۭ وَنَجْعَلَهُمُ ٱلْوَٰرِثِينَ", transliteration: "Wanureedu an namunna AAala allatheena istudAAifoo fee alardi wanajAAalahum aimmatan wanajAAalahumu alwaritheena", transliterationB: "Wa nureedu an namunna 'alal lazeenas tud'ifoo fil ardi wa naj'alahum a'immatanw wa naj'alahumul waariseen", english: "And We wished to be Gracious to those who were being depressed in the land, to make them leaders (in Faith) and make them heirs", romanUrdu: "Aur hum yeh irada rakhte thay ke meharbani karein un logon par jo zameen mein zaleel karke rakkhey gaye thay, aur unhein peshwa(leaders) bana dein, aur unhi ko waris banayein" },
    { number: 6, arabic: "وَنُمَكِّنَ لَهُمْ فِى ٱلْأَرْضِ وَنُرِىَ فِرْعَوْنَ وَهَٰمَٰنَ وَجُنُودَهُمَا مِنْهُم مَّا كَانُوا۟ يَحْذَرُونَ", transliteration: "Wanumakkina lahum fee alardi wanuriya firAAawna wahamana wajunoodahuma minhum ma kanoo yahtharoona", transliterationB: "Wa numakkina lahum fil ardi wa nuriya Fir'awna wa Haamaana wa junoodahumaa minhum maa kaanoo yahzaroon", english: "To establish a firm place for them in the land, and to show Pharaoh, Haman, and their hosts, at their hands, the very things against which they were taking precautions", romanUrdu: "Aur zameen mein unko iqtedar(power) bakshein, aur unse Firoun o Hamaan aur unke lashkaron ko wahi kuch dikhla dein jiska unhein darr tha" },
    { number: 7, arabic: "وَأَوْحَيْنَآ إِلَىٰٓ أُمِّ مُوسَىٰٓ أَنْ أَرْضِعِيهِ ۖ فَإِذَا خِفْتِ عَلَيْهِ فَأَلْقِيهِ فِى ٱلْيَمِّ وَلَا تَخَافِى وَلَا تَحْزَنِىٓ ۖ إِنَّا رَآدُّوهُ إِلَيْكِ وَجَاعِلُوهُ مِنَ ٱلْمُرْسَلِينَ", transliteration: "Waawhayna ila ommi moosa an ardiAAeehi faitha khifti AAalayhi faalqeehi fee alyammi wala takhafee wala tahzanee inna raddoohu ilayki wajaAAiloohu mina almursaleena", transliterationB: "Wa awhainaaa ilaaa ummi Moosaaa an ardi'eehi faizaa khifti 'alaihi fa alqeehi filyammi wa laa takhaafee wa laa tahzaneee innaa raaaddoohu ilaiki wa jaa'iloohu minal mursaleen", english: "So We sent this inspiration to the mother of Moses: \"Suckle (thy child), but when thou hast fears about him, cast him into the river, but fear not nor grieve: for We shall restore him to thee, and We shall make him one of Our messengers", romanUrdu: "Humne Moosa ki Maa ko ishara kiya ke “Isko doodh pila, phir jab tujhey uski jaan ka khatra ho to isey dariya mein daal de aur kuch khauf aur gham na kar, hum isey terey hi paas wapas le aayenge, aur isko paighambaron mein shamil karenge”" },
    { number: 8, arabic: "فَٱلْتَقَطَهُۥٓ ءَالُ فِرْعَوْنَ لِيَكُونَ لَهُمْ عَدُوًّۭا وَحَزَنًا ۗ إِنَّ فِرْعَوْنَ وَهَٰمَٰنَ وَجُنُودَهُمَا كَانُوا۟ خَٰطِـِٔينَ", transliteration: "Failtaqatahu alu firAAawna liyakoona lahum AAaduwwan wahazanan inna firAAawna wahamana wajunoodahuma kanoo khatieena", transliterationB: "Faltaqatahooo Aalu Fir'awna li yakoona lahum 'aduwwanw wa hazanaa; inna Fir'awna wa Haamaana wa junooda humaa kaanoo khaati'een", english: "Then the people of Pharaoh picked him up (from the river): (It was intended) that (Moses) should be to them an adversary and a cause of sorrow: for Pharaoh and Haman and (all) their hosts were men of sin", romanUrdu: "Aakhir e kaar Firoun ke ghar walon ne usey (dariya se) nikal liya taa-ke woh unka dushman aur unke liye sabab e ranj baney. Waqayi Firoun aur Hamaan aur uske lashkar (apni tadbeer mein ) baday galat-kaar thay" },
    { number: 9, arabic: "وَقَالَتِ ٱمْرَأَتُ فِرْعَوْنَ قُرَّتُ عَيْنٍۢ لِّى وَلَكَ ۖ لَا تَقْتُلُوهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًۭا وَهُمْ لَا يَشْعُرُونَ", transliteration: "Waqalati imraatu firAAawna qurratu AAaynin lee walaka la taqtuloohu AAasa an yanfaAAana aw nattakhithahu waladan wahum la yashAAuroona", transliterationB: "Wa qaalatim ra atu Fir'awna qurratu 'aynil lee wa lak; laa taqtuloohu 'asaaa aiyanfa'anaa aw nattakhizahoo waladanw wa hum laa yash'uroon", english: "The wife of Pharaoh said: \"(Here is) joy of the eye, for me and for thee: slay him not. It may be that he will be use to us, or we may adopt him as a son.\" And they perceived not (what they were doing)", romanUrdu: "Firoun ki biwi ne (ussey) kaha “yeh mere aur tere liye aankhon ki thandak hai, isey qatal na karo, kya ajab ke yeh hamare liye mufeed saabit ho, ya hum isey beta hi bana lein.” Aur woh (anjaam se) bekhabar thay" },
    { number: 10, arabic: "وَأَصْبَحَ فُؤَادُ أُمِّ مُوسَىٰ فَٰرِغًا ۖ إِن كَادَتْ لَتُبْدِى بِهِۦ لَوْلَآ أَن رَّبَطْنَا عَلَىٰ قَلْبِهَا لِتَكُونَ مِنَ ٱلْمُؤْمِنِينَ", transliteration: "Waasbaha fuadu ommi moosa farighan in kadat latubdee bihi lawla an rabatna AAala qalbiha litakoona mina almumineena", transliterationB: "Wa asbaha fu'aadu ummi Moosaa faarighan in kaadat latubdee bihee law laaa arrabatnaa 'alaa qalbihaa litakoona minal mu'mineen", english: "But there came to be a void in the heart of the mother of Moses: She was going almost to disclose his (case), had We not strengthened her heart (with faith), so that she might remain a (firm) believer", romanUrdu: "Udhar Moosa ki Maa ka dil uda jaa raha tha, woh is raaz ko faash kar baithti agar hum uski dharas(strengthened her heart ) na bandha detey taa-ke woh ( hamare wadey par) iman laney walon mein se ho" },
    { number: 11, arabic: "وَقَالَتْ لِأُخْتِهِۦ قُصِّيهِ ۖ فَبَصُرَتْ بِهِۦ عَن جُنُبٍۢ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Waqalat liokhtihi qusseehi fabasurat bihi AAan junubin wahum la yashAAuroona", transliterationB: "Wa qaalat li ukhtihee qusseehi fabasurat bihee 'an junubinw wahum laa yash'uroon", english: "And she said to the sister of (Moses), \"Follow him\" so she (the sister) watched him in the character of a stranger. And they knew not", romanUrdu: "Usne bachhey ki behan se kaha iske peechey peechey ja, chunanchey woh alag se usko is tarah dekhti rahi ke (dushmano ko) uska pata na chala" },
    { number: 12, arabic: "۞ وَحَرَّمْنَا عَلَيْهِ ٱلْمَرَاضِعَ مِن قَبْلُ فَقَالَتْ هَلْ أَدُلُّكُمْ عَلَىٰٓ أَهْلِ بَيْتٍۢ يَكْفُلُونَهُۥ لَكُمْ وَهُمْ لَهُۥ نَٰصِحُونَ", transliteration: "Waharramna AAalayhi almaradiAAa min qablu faqalat hal adullukum AAala ahli baytin yakfuloonahu lakum wahum lahu nasihoona", transliterationB: "Wa harramnaa 'alaihil maraadi'a min qablu faqaalat hal adullukum 'alaaa ahli baitiny yakfuloonahoo lakum wa hum lahoo naasihoon", english: "And we ordained that he refused suck at first, until (His sister came up and) said: \"Shall I point out to you the people of a house that will nourish and bring him up for you and be sincerely attached to him", romanUrdu: "Aur humne bacchey par pehle hi doodh pilane waliyon ki chatiyan (breasts) haraam kar rakkhi thi. (Yeh halat dekh kar) us ladki ne unsey kaha “main tumhein aisey ghar ka pata bataon jiske log iski parwarish ka zimma lein aur khair khwahi ke saath isey rakkhein?”" },
    { number: 13, arabic: "فَرَدَدْنَٰهُ إِلَىٰٓ أُمِّهِۦ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ وَلِتَعْلَمَ أَنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", transliteration: "Faradadnahu ila ommihi kay taqarra AAaynuha wala tahzana walitaAAlama anna waAAda Allahi haqqun walakinna aktharahum la yaAAlamoona", transliterationB: "Faradadnaahu ilaa ummihee kai taqarra 'ainuhaa wa laa tahzana wa lita'lama anna wa'dal laahi haqqunw wa laakinna aksarahum laa ya'lamoon", english: "Thus did We restore him to his mother, that her eye might be comforted, that she might not grieve, and that she might know that the promise of Allah is true: but most of them do not understand", romanUrdu: "Is tarah hum Moosa ko uski Maa ke paas palta laaye taa-ke uski aankhein thandi hon aur woh ghamgheen na ho. Aur jaan le ke Allah ka wada saccha tha, magar aksar log is baat ko nahin jaantey" },
    { number: 14, arabic: "وَلَمَّا بَلَغَ أَشُدَّهُۥ وَٱسْتَوَىٰٓ ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Walamma balagha ashuddahu waistawa ataynahu hukman waAAilman wakathalika najzee almuhsineena", transliterationB: "Wa lammaa balagha ashuddahoo wastawaaa aatai naahu hukmanw wa 'ilmaa; wa kazaalika najzil muhsineen", english: "When he reached full age, and was firmly established (in life), We bestowed on him wisdom and knowledge: for thus do We reward those who do good", romanUrdu: "Phir jab Moosa apni poori jawani ko pahunch gaya aur uska nasho-numa mukammal ho gaya to humne usey hukum aur ilm ata kiya. Hum neik logon ko aisi hi jazaa detey hain" },
    { number: 15, arabic: "وَدَخَلَ ٱلْمَدِينَةَ عَلَىٰ حِينِ غَفْلَةٍۢ مِّنْ أَهْلِهَا فَوَجَدَ فِيهَا رَجُلَيْنِ يَقْتَتِلَانِ هَٰذَا مِن شِيعَتِهِۦ وَهَٰذَا مِنْ عَدُوِّهِۦ ۖ فَٱسْتَغَٰثَهُ ٱلَّذِى مِن شِيعَتِهِۦ عَلَى ٱلَّذِى مِنْ عَدُوِّهِۦ فَوَكَزَهُۥ مُوسَىٰ فَقَضَىٰ عَلَيْهِ ۖ قَالَ هَٰذَا مِنْ عَمَلِ ٱلشَّيْطَٰنِ ۖ إِنَّهُۥ عَدُوٌّۭ مُّضِلٌّۭ مُّبِينٌۭ", transliteration: "Wadakhala almadeenata AAala heeni ghaflatin min ahliha fawajada feeha rajulayni yaqtatilani hatha min sheeAAatihi wahatha min AAaduwwihi faistaghathahu allathee min sheeAAatihi AAala allathee min AAaduwwihi fawakazahu moosa faqada AAalayhi qala hatha min AAamali alshshaytani innahu AAaduwwun mudillun mubeenun", transliterationB: "Wa dakhalal madeenata 'alaa heene ghaflatim min ahlihaa fawajada feeha raju laini yaqtatilaani haazaa min shee'atihee wa haaza min 'aduwwihee fastaghaasahul lazee min shee'atihee 'alal lazee min 'aduwwihee fawakazahoo Moosaa faqadaa 'alaihi qaala haaza min 'amalish Shaitaani innahoo 'aduwwum mmudillum mubeen", english: "And he entered the city at a time when its people were not watching: and he found there two men fighting,- one of his own religion, and the other, of his foes. Now the man of his own religion appealed to him against his foe, and Moses struck him with his fist and made an end of him. He said: \"This is a work of Evil (Satan): for he is an enemy that manifestly misleads", romanUrdu: "(Ek roz) woh shehar mein aisey waqt mein dakhil hua jabke ehle shehar gaflat mein thay. Wahan usne dekha ke do aadmi laddh rahey hain, ek uski apni qaum ka tha aur dusra uski dushman qaum se taaluq rakhta tha.Uski qaum ke aadmi ne dushman qaum waley ke khilaf usey madad ke liye pukara. Moosa ne usko ek ghoosa (fist) maara aur uska kaam tamaam kardiya. (Yeh harakat sarzad hotey hi)Moosa ne kaha “yeh Shaytaan ki kaar farmayi hai, woh sakht dushman aur khula gumraah kun hai”" },
    { number: 16, arabic: "قَالَ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى فَٱغْفِرْ لِى فَغَفَرَ لَهُۥٓ ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", transliteration: "Qala rabbi innee thalamtu nafsee faighfir lee faghafara lahu innahu huwa alghafooru alrraheemu", transliterationB: "Qaala Rabbi innee zalamtu nafsee faghfir lee faghafaralah; innahoo Huwal Ghafoorur Raheem", english: "He prayed: \"O my Lord! I have indeed wronged my soul! Do Thou then forgive me!\" So (Allah) forgave him: for He is the Oft-Forgiving, Most Merciful", romanUrdu: "Phir woh kehne laga “Aey mere Rubb, maine apne nafs par bada zulm kar daala, meri magfirat farma de.”Chunanchey Allah ne uski magfirat farma di, woh gafoor o raheem hai" },
    { number: 17, arabic: "قَالَ رَبِّ بِمَآ أَنْعَمْتَ عَلَىَّ فَلَنْ أَكُونَ ظَهِيرًۭا لِّلْمُجْرِمِينَ", transliteration: "Qala rabbi bima anAAamta AAalayya falan akoona thaheeran lilmujrimeena", transliterationB: "Qaala Rabbi bimaaa an'amta 'alaiya falan akoona zaheeral lilmujrimeen", english: "He said: \"O my Lord! For that Thou hast bestowed Thy Grace on me, never shall I be a help to those who sin", romanUrdu: "Mossa ne ahad kiya ke “Aey mere Rubb, yeh ehsan jo tu nay mujhpar kiya hai iske baad ab main kabhi mujrimon ka madadgaar na banunga”" },
    { number: 18, arabic: "فَأَصْبَحَ فِى ٱلْمَدِينَةِ خَآئِفًۭا يَتَرَقَّبُ فَإِذَا ٱلَّذِى ٱسْتَنصَرَهُۥ بِٱلْأَمْسِ يَسْتَصْرِخُهُۥ ۚ قَالَ لَهُۥ مُوسَىٰٓ إِنَّكَ لَغَوِىٌّۭ مُّبِينٌۭ", transliteration: "Faasbaha fee almadeenati khaifan yataraqqabu faitha allathee istansarahu bialamsi yastasrikhuhu qala lahu moosa innaka laghawiyyun mubeenun", transliterationB: "Fa asbaha fil madeenati khaaa'ifany yataraqqabu fa izal lazis tansarahoo bil amsi yastasrikhuh; qaala lahoo moosaaa innaka laghawiyyum mubeen", english: "So he saw the morning in the city, looking about, in a state of fear, when behold, the man who had, the day before, sought his help called aloud for his help (again). Moses said to him: \"Thou art truly, it is clear, a quarrelsome fellow", romanUrdu: "Dusre roz woh subah saware darta aur har taraf se khatra bhampta hua shehar mein jaa raha tha ke yakayak kya dekhta hai ke wahi shaks jisne kal usey madad ke liye pukara tha aaj phir usey pukar raha hai. Mossa ne kaha “tu to bada hi behka hua aadmi hai”" },
    { number: 19, arabic: "فَلَمَّآ أَنْ أَرَادَ أَن يَبْطِشَ بِٱلَّذِى هُوَ عَدُوٌّۭ لَّهُمَا قَالَ يَٰمُوسَىٰٓ أَتُرِيدُ أَن تَقْتُلَنِى كَمَا قَتَلْتَ نَفْسًۢا بِٱلْأَمْسِ ۖ إِن تُرِيدُ إِلَّآ أَن تَكُونَ جَبَّارًۭا فِى ٱلْأَرْضِ وَمَا تُرِيدُ أَن تَكُونَ مِنَ ٱلْمُصْلِحِينَ", transliteration: "Falamma an arada an yabtisha biallathee huwa AAaduwwun lahuma qala ya moosa atureedu an taqtulanee kama qatalta nafsan bialamsi in tureedu illa an takoona jabbaran fee alardi wama tureedu an takoona mina almusliheena", transliterationB: "Falammaaa an araada ai yabtisha billazee huwa 'aduwwul lahumaa qaala yaa Moosaaa atureedu an taqtulanee kamaa qatalta nafsam bil amsi in tureedu illaaa an takoona jabbaaram fil ardi wa maa tureedu an takoona minal musliheen", english: "Then, when he decided to lay hold of the man who was an enemy to both of them, that man said: \"O Moses! Is it thy intention to slay me as thou slewest a man yesterday? Thy intention is none other than to become a powerful violent man in the land, and not to be one who sets things right", romanUrdu: "Phir jab Moosa ne irada kiya ke dushman qaum ke aadmi par hamla karey to woh pukar uttha “Aey Moosa , kya aaj tu mujhey usi tarah qatal karne laga hai jis tarah kal ek shaks ko qatal kar chuka hai, tu is mulk mein jabbar ban kar rehna chahta hai, Islaah nahin karna chahta”" },
    { number: 20, arabic: "وَجَآءَ رَجُلٌۭ مِّنْ أَقْصَا ٱلْمَدِينَةِ يَسْعَىٰ قَالَ يَٰمُوسَىٰٓ إِنَّ ٱلْمَلَأَ يَأْتَمِرُونَ بِكَ لِيَقْتُلُوكَ فَٱخْرُجْ إِنِّى لَكَ مِنَ ٱلنَّٰصِحِينَ", transliteration: "Wajaa rajulun min aqsa almadeenati yasAAa qala ya moosa inna almalaa yatamiroona bika liyaqtulooka faokhruj innee laka mina alnnasiheena", transliterationB: "Wa jaaa'a rajulum min aqsal madeenati yas'aa qaala yaa Moosaaa innal mala a yaa tamiroona bika liyaqtulooka fakhruj innee laka minan naasiheen", english: "And there came a man, running, from the furthest end of the City. He said: \"O Moses! the Chiefs are taking counsel together about thee, to slay thee: so get thee away, for I do give thee sincere advice", romanUrdu: "Iske baad ek aadmi shehar ke parle sirey (other end of the city) se daudta hua aaya aur bola “Moosa , sardaron mein tere qatal ke mashwarey ho rahey hain, yahan se nikal jaa, main tera khair khwa(wellwisher) hoon”" },
    { number: 21, arabic: "فَخَرَجَ مِنْهَا خَآئِفًۭا يَتَرَقَّبُ ۖ قَالَ رَبِّ نَجِّنِى مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Fakharaja minha khaifan yataraqqabu qala rabbi najjinee mina alqawmi alththalimeena", transliterationB: "Fakharaja minhaa khaaa 'ifany-yataraqqab; qaala Rabbi najjinee minal qawmiz zaalimeen", english: "He therefore got away therefrom, looking about, in a state of fear. He prayed \"O my Lord! save me from people given to wrong-doing", romanUrdu: "Yeh khabar sunte hi Moosa darta aur sehamta nikal khada hua aur usne dua ki ke “Aey mere Rubb, mujhey zaalimon se bacha”" },
    { number: 22, arabic: "وَلَمَّا تَوَجَّهَ تِلْقَآءَ مَدْيَنَ قَالَ عَسَىٰ رَبِّىٓ أَن يَهْدِيَنِى سَوَآءَ ٱلسَّبِيلِ", transliteration: "Walamma tawajjaha tilqaa madyana qala AAasa rabbee an yahdiyanee sawaa alssabeeli", transliterationB: "Wa lammaa tawajjaha tilqaaa'a Madyana qaala 'asaa Rabbeee ai yahdiyanee Sawaaa'as Sabeel", english: "Then, when he turned his face towards (the land of) Madyan, he said: \"I do hope that my Lord will show me the smooth and straight Path", romanUrdu: "(Misr se nikal kar) jab Moosa ne Madiyan ka rukh kiya to usne kaha “ Umeed hai ke mera Rubb mujhey theek raaste par daal dega”" },
    { number: 23, arabic: "وَلَمَّا وَرَدَ مَآءَ مَدْيَنَ وَجَدَ عَلَيْهِ أُمَّةًۭ مِّنَ ٱلنَّاسِ يَسْقُونَ وَوَجَدَ مِن دُونِهِمُ ٱمْرَأَتَيْنِ تَذُودَانِ ۖ قَالَ مَا خَطْبُكُمَا ۖ قَالَتَا لَا نَسْقِى حَتَّىٰ يُصْدِرَ ٱلرِّعَآءُ ۖ وَأَبُونَا شَيْخٌۭ كَبِيرٌۭ", transliteration: "Walamma warada maa madyana wajada AAalayhi ommatan mina alnnasi yasqoona wawajada min doonihimu imraatayni tathoodani qala ma khatbukuma qalata la nasqee hatta yusdira alrriAAao waaboona shaykhun kabeerun", transliterationB: "Wa lammaa warada maaa'a Madyana wajada 'alaihi ummatam minannaasi yasqoona wa wajada min doonihimum ra ataini tazoodaani qaala maa khatubkumaa qaalataa laa nasqee hataa yusdirar ri'aaa'u wa aboonaa shaikhun kabeer", english: "And when he arrived at the watering (place) in Madyan, he found there a group of men watering (their flocks), and besides them he found two women who were keeping back (their flocks). He said: \"What is the matter with you?\" They said: \"We cannot water (our flocks) until the shepherds take back (their flocks): And our father is a very old man", romanUrdu: "Aur jab woh Madiyan ke kunwein (well) par pahuncha to usne dekha ke bahut se log apne jaanwaron ko pani pila rahey hain, aur unsey alag ek taraf do auratein apne jaanwaron ko rok rahi hain. Moosa ne in auraton se pucha “tumhein kya pareshani hai?” unhon ne kaha “Hum apne jaanwaron ko pani nahin pila sakti jab tak yeh charwahe apne jaanwar nikal kar na le jayein, aur hamare waalid ek bahut boodey aadmi hain”" },
    { number: 24, arabic: "فَسَقَىٰ لَهُمَا ثُمَّ تَوَلَّىٰٓ إِلَى ٱلظِّلِّ فَقَالَ رَبِّ إِنِّى لِمَآ أَنزَلْتَ إِلَىَّ مِنْ خَيْرٍۢ فَقِيرٌۭ", transliteration: "Fasaqa lahuma thumma tawalla ila alththilli faqala rabbi innee lima anzalta ilayya min khayrin faqeerun", transliterationB: "Fasaqaa lahumaa summa tawallaaa ilaz zilli faqaala Rabbi innee limaaa anzalta ilaiya min khairin faqeer", english: "So he watered (their flocks) for them; then he turned back to the shade, and said:\"O my Lord! truly am I in (desperate) need of any good that Thou dost send me", romanUrdu: "Yeh sunkar Moosa ne unke jaanwaron ko pani pila diya, phir ek saaye ki jagah jaa baitha aur bola “parwardigar, jo khair bhi tu mujhpar nazil karde main uska mohtaj hoon.”" },
    { number: 25, arabic: "فَجَآءَتْهُ إِحْدَىٰهُمَا تَمْشِى عَلَى ٱسْتِحْيَآءٍۢ قَالَتْ إِنَّ أَبِى يَدْعُوكَ لِيَجْزِيَكَ أَجْرَ مَا سَقَيْتَ لَنَا ۚ فَلَمَّا جَآءَهُۥ وَقَصَّ عَلَيْهِ ٱلْقَصَصَ قَالَ لَا تَخَفْ ۖ نَجَوْتَ مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Fajaathu ihdahuma tamshee AAala istihyain qalat inna abee yadAAooka liyajziyaka ajra ma saqayta lana falamma jaahu waqassa AAalayhi alqasasa qala la takhaf najawta mina alqawmi alththalimeena", transliterationB: "Fajaaa'at hu ihdaahumaa tamshee 'alas tihyaaa'in qaalat inna abee yad'ooka li yajziyaka ajra maa saqaita lanaa; falammaa jaaa'ahoo wa qassa 'alaihil qasasa qaala laa takhaf najawta minal qawmiz zaalimeen", english: "Afterwards one of the (damsels) came (back) to him, walking bashfully. She said: \"My father invites thee that he may reward thee for having watered (our flocks) for us.\" So when he came to him and narrated the story, he said: \"Fear thou not: (well) hast thou escaped from unjust people", romanUrdu: "(Kuch dair na guzri thi ke) un dono auraton mein se ek sharam o haya se chalti hui uske paas aayi aur kehne lagi “Mere waalid aap ko bula rahey hain taa-ke aapne hamare jaanwaron ko pani jo pilaya hai uska ajar aapko dein.” Moosa jab uske paas pahuncha aur apna saara qissa usey sunaya to usne kaha “kuch khauf na karo, ab tum zaalimon se bach nikle ho.”" },
    { number: 26, arabic: "قَالَتْ إِحْدَىٰهُمَا يَٰٓأَبَتِ ٱسْتَـْٔجِرْهُ ۖ إِنَّ خَيْرَ مَنِ ٱسْتَـْٔجَرْتَ ٱلْقَوِىُّ ٱلْأَمِينُ", transliteration: "Qalat ihdahuma ya abati istajirhu inna khayra mani istajarta alqawiyyu alameenu", transliterationB: "Qaalat ihdaahumaa yaaa abatis taajirhu inna khaira manistaajartal qawiyyul ameen", english: "Said one of the (damsels): \"O my (dear) father! engage him on wages: truly the best of men for thee to employ is the (man) who is strong and trusty", romanUrdu: "In dono auraton mein se ek ne apne baap se kaha “abbajaan is shaks ko naukar rakh lijiye, behtareen aadmi jisey aap mulazim rakhein wahi ho sakta hai jo mazboot aur amaanat-daar ho”" },
    { number: 27, arabic: "قَالَ إِنِّىٓ أُرِيدُ أَنْ أُنكِحَكَ إِحْدَى ٱبْنَتَىَّ هَٰتَيْنِ عَلَىٰٓ أَن تَأْجُرَنِى ثَمَٰنِىَ حِجَجٍۢ ۖ فَإِنْ أَتْمَمْتَ عَشْرًۭا فَمِنْ عِندِكَ ۖ وَمَآ أُرِيدُ أَنْ أَشُقَّ عَلَيْكَ ۚ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ مِنَ ٱلصَّٰلِحِينَ", transliteration: "Qala innee oreedu an onkihaka ihda ibnatayya hatayni AAala an tajuranee thamaniya hijajin fain atmamta AAashran famin AAindika wama oreedu an ashuqqa AAalayka satajidunee in shaa Allahu mina alssaliheena", transliterationB: "Qaala innee ureedu an unkihaka ihdab nataiya haataini 'alaaa an taajuranee samaaniya hijaj; fa in atmamta 'ashran famin 'indika wa maaa ureedu an ashuqqa 'alaik; satajiduneee in shaaa'al laahu minas saaliheen", english: "He said: \"I intend to wed one of these my daughters to thee, on condition that thou serve me for eight years; but if thou complete ten years, it will be (grace) from thee. But I intend not to place thee under a difficulty: thou wilt find me, indeed, if Allah wills, one of the righteous", romanUrdu: "Uske baap ne (Moosa se) kaha “main chahta hoon ke apni in do betiyon mein se ek ka nikah tumhare saath kardoon bashart yeh ke tum aath(eight) saal tak mere haan mulazimat karo, aur agar dus saal purey kardo to yeh tumhari marzi hai. Main tumpar sakhti nahin karna chahta, tum insha Allah mujhey neik aadmi paogey”" },
    { number: 28, arabic: "قَالَ ذَٰلِكَ بَيْنِى وَبَيْنَكَ ۖ أَيَّمَا ٱلْأَجَلَيْنِ قَضَيْتُ فَلَا عُدْوَٰنَ عَلَىَّ ۖ وَٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌۭ", transliteration: "Qala thalika baynee wabaynaka ayyama alajalayni qadaytu fala AAudwana AAalayya waAllahu AAala ma naqoolu wakeelun", transliterationB: "Qaala zaalika bainee wa bainaka aiyamal ajalaini qadaitu falaa 'udwaana 'alaiya wallaahu 'alaa ma naqoolu Wakeel", english: "He said: \"Be that (the agreement) between me and thee: whichever of the two terms I fulfil, let there be no ill-will to me. Be Allah a witness to what we say", romanUrdu: "Mossa ne jawab diya “yeh baat mere aur aapke darmiyan tai ho gayi.In dono muddaton mein se jo bhi main poori kardoon uske baad phir koi zyadati mujhpar na ho, aur jo kuch qaul o qaraar hum kar rahey hain Allah uspar nigehbaan hai.”" },
    { number: 29, arabic: "۞ فَلَمَّا قَضَىٰ مُوسَى ٱلْأَجَلَ وَسَارَ بِأَهْلِهِۦٓ ءَانَسَ مِن جَانِبِ ٱلطُّورِ نَارًۭا قَالَ لِأَهْلِهِ ٱمْكُثُوٓا۟ إِنِّىٓ ءَانَسْتُ نَارًۭا لَّعَلِّىٓ ءَاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ جَذْوَةٍۢ مِّنَ ٱلنَّارِ لَعَلَّكُمْ تَصْطَلُونَ", transliteration: "Falamma qada moosaalajala wasara biahlihi anasa min janibi alttoori naran qala liahlihi omkuthoo innee anastu naran laAAallee ateekum minha bikhabarin aw jathwatin mina alnnari laAAallakum tastaloona", transliterationB: "Falammmaa qadaa Moosal ajala wa saara bi ahliheee aanasa min jaanibit Toori naaran qaala li ahlihim kusooo inneee aanastu naaral la 'alleee aateekum minhaa bikhabarin aw jazwatim minan naari la 'allakum tastaloon", english: "Now when Moses had fulfilled the term, and was travelling with his family, he perceived a fire in the direction of Mount Tur. He said to his family: \"Tarry ye; I perceive a fire; I hope to bring you from there some information, or a burning firebrand, that ye may warm yourselves", romanUrdu: "Jab Moosa ne muddat poori kardi aur woh apne ehal-o-aayal(family) ko lekar chala to Toor ki jaanib usko ek aag nazar aayi.Usne apne ghar walon se kaha “thehro, maine ek aag dekhi hai, shayad main wahan se koi khabar le aaoon ya is aag se koi angara hi utha laaon jissey tum taap sako.”" },
    { number: 30, arabic: "فَلَمَّآ أَتَىٰهَا نُودِىَ مِن شَٰطِئِ ٱلْوَادِ ٱلْأَيْمَنِ فِى ٱلْبُقْعَةِ ٱلْمُبَٰرَكَةِ مِنَ ٱلشَّجَرَةِ أَن يَٰمُوسَىٰٓ إِنِّىٓ أَنَا ٱللَّهُ رَبُّ ٱلْعَٰلَمِينَ", transliteration: "Falamma ataha noodiya min shatii alwadi alaymani fee albuqAAati almubarakati mina alshshajarati an ya moosa innee ana Allahu rabbu alAAalameena", transliterationB: "Falammaaa ataahaa noodiya min shaati'il waadil aimani fil buq'atil muubaarakati minash shajarati ai yaa Moosaaa inneee Anal laahu Rabbul 'aalameen", english: "But when he came to the (fire), a voice was heard from the right bank of the valley, from a tree in hallowed ground: \"O Moses! Verily I am Allah, the Lord of the Worlds", romanUrdu: "Wahan pahuncha to wadi ke dahine kinarey par mubarak khittey mein ek darakht se pukara gaya ke “Aey Moosa, main hi Allah hoon, sarey jahaan walon ka maalik”" },
    { number: 31, arabic: "وَأَنْ أَلْقِ عَصَاكَ ۖ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّۭ وَلَّىٰ مُدْبِرًۭا وَلَمْ يُعَقِّبْ ۚ يَٰمُوسَىٰٓ أَقْبِلْ وَلَا تَخَفْ ۖ إِنَّكَ مِنَ ٱلْءَامِنِينَ", transliteration: "Waan alqi AAasaka falamma raaha tahtazzu kaannaha jannun walla mudbiran walam yuAAaqqib ya moosa aqbil wala takhaf innaka mina alamineena", transliterationB: "Wa an alqi 'asaaka falam maa ra aahaa tahtazzu ka annnahaa jaaannunw wallaa mudbiranw wa lam yu'aqqib; yaa Moosaa aqbil wa laa takhaf innaka minal aamineen", english: "Now do thou throw thy rod!\" but when he saw it moving (of its own accord) as if it had been a snake, he turned back in retreat, and retraced not his steps: O Moses!\" (It was said), \"Draw near, and fear not: for thou art of those who are secure", romanUrdu: "Aur (hukum diya gaya ke) “phenk de apni laathi.”Junhi ke Moosa ne dekha ke woh laathi saanp (snake) ki tarah bal kha rahi hai to woh peeth pher kar bhaaga aur unse mudh kar bhi na dekha. (Irshad hua) “Moosa, palat aa aur khauf na kar, tu bilkul mehfuz hai" },
    { number: 32, arabic: "ٱسْلُكْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍۢ وَٱضْمُمْ إِلَيْكَ جَنَاحَكَ مِنَ ٱلرَّهْبِ ۖ فَذَٰنِكَ بُرْهَٰنَانِ مِن رَّبِّكَ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ", transliteration: "Osluk yadaka fee jaybika takhruj baydaa min ghayri sooin waodmum ilayka janahaka mina alrrahbi fathanika burhanani min rabbika ila firAAawna wamalaihi innahum kanoo qawman fasiqeena", transliterationB: "Usluk yadaka fee jaibika takhruj baidaaa'a min ghairi sooo'inw wadmum ilaika janaahaka minar rahbi fazaanika burhaanaani mir Rabbika ilaa Fiw'awna wa mala'ih; innahum kaanoo qawman faasiqeen", english: "Move thy hand into thy bosom, and it will come forth white without stain (or harm), and draw thy hand close to thy side (to guard) against fear. Those are the two credentials from thy Lord to Pharaoh and his Chiefs: for truly they are a people rebellious and wicked", romanUrdu: "Apna haath girehban mein daal, chamakta hua niklega bagair kisi takleef ke aur khauf se bachne ke liye apna baazu bhench le(fold back). Yeh do roshan nishaniyan hain tere Rubb ki taraf se Firoun aur uske darbariyon ke saamne pesh karne ke liye, woh badey hi nafarmaan log hain”" },
    { number: 33, arabic: "قَالَ رَبِّ إِنِّى قَتَلْتُ مِنْهُمْ نَفْسًۭا فَأَخَافُ أَن يَقْتُلُونِ", transliteration: "Qala rabbi innee qataltu minhum nafsan faakhafu an yaqtulooni", transliterationB: "Qaala Rabbi innee qataltu minhum nafsan fa akhaafu ai yaqtuloon", english: "He said: \"O my Lord! I have slain a man among them, and I fear lest they slay me", romanUrdu: "Moosa ne arz kiya “Mere aaqa, main to unka ek aadmi qatal kar chuka hoon, darta hoon ke woh mujhey maar daalenge" },
    { number: 34, arabic: "وَأَخِى هَٰرُونُ هُوَ أَفْصَحُ مِنِّى لِسَانًۭا فَأَرْسِلْهُ مَعِىَ رِدْءًۭا يُصَدِّقُنِىٓ ۖ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ", transliteration: "Waakhee haroonu huwa afsahu minnee lisanan faarsilhu maAAiya ridan yusaddiqunee innee akhafu an yukaththibooni", transliterationB: "Wa akhee Haaroonu huwa afsahu minnee lisaanan fa arsilhu ma'iya rid ai yusaddiquneee innee akhaafu ai yukazziboon", english: "And my brother Aaron - He is more eloquent in speech than I: so send him with me as a helper, to confirm (and strengthen) me: for I fear that they may accuse me of falsehood", romanUrdu: "Aur mera bhai Haroon mujhse zyada zubaan awar (eloquent of tongue) hai, usey mere saath madadgaar ke taur par bhej taa-ke woh meri taaeed (support) karey, mujhey andesha hai ke woh log mujhey jhutlayenge.”" },
    { number: 35, arabic: "قَالَ سَنَشُدُّ عَضُدَكَ بِأَخِيكَ وَنَجْعَلُ لَكُمَا سُلْطَٰنًۭا فَلَا يَصِلُونَ إِلَيْكُمَا ۚ بِـَٔايَٰتِنَآ أَنتُمَا وَمَنِ ٱتَّبَعَكُمَا ٱلْغَٰلِبُونَ", transliteration: "Qala sanashuddu AAadudaka biakheeka wanajAAalu lakuma sultanan fala yasiloona ilaykuma biayatina antuma wamani ittabaAAakuma alghaliboona", transliterationB: "Qaala sanashuddu 'adudaka bi akheeka wa naj'alu lakumaa sultaanan falaa yasiloona ilaikumaa; bi Aayaatinaa antumaa wa manit taba'akumal ghaaliboon", english: "He said: \"We will certainly strengthen thy arm through thy brother, and invest you both with authority, so they shall not be able to touch you: with Our Sign shall ye triumph,- you two as well as those who follow you", romanUrdu: "Farmaya “hum tere bhai ke zariye se tera haath mazboot karenge aur tum dono ko aisi sitwat(authority) bakshenge ke woh tumhara kuch na bigaad sakenge.Hamari nishaniyon ke zoar se galaba (triumph) tumhare aur tumhare pairawon ka hi hoga”" },
    { number: 36, arabic: "فَلَمَّا جَآءَهُم مُّوسَىٰ بِـَٔايَٰتِنَا بَيِّنَٰتٍۢ قَالُوا۟ مَا هَٰذَآ إِلَّا سِحْرٌۭ مُّفْتَرًۭى وَمَا سَمِعْنَا بِهَٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ", transliteration: "Falamma jaahum moosa biayatina bayyinatin qaloo ma hatha illa sihrun muftaran wama samiAAna bihatha fee abaina alawwaleena", transliterationB: "Falammaa jaaa'ahum Moosaa bi Aayaatinaa baiyinaatin qaaloo maa haazaaa illaa sihrum muftaranw wa maa sami'naa bihaazaa feee aabaaa'inal awwaleen", english: "When Moses came to them with Our clear signs, they said: \"This is nothing but sorcery faked up: never did we head the like among our fathers of old", romanUrdu: "Phir jab Moosa un logon ke paas hamari khuli khuli nishaniyan lekar pahuncha to unhon ne kaha ke yeh kuch nahin hai magar banawati jaadu aur yeh baatein to humne apne baap dada ke zamane mein kabhi suni hi nahin" },
    { number: 37, arabic: "وَقَالَ مُوسَىٰ رَبِّىٓ أَعْلَمُ بِمَن جَآءَ بِٱلْهُدَىٰ مِنْ عِندِهِۦ وَمَن تَكُونُ لَهُۥ عَٰقِبَةُ ٱلدَّارِ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّٰلِمُونَ", transliteration: "Waqala moosa rabbee aAAlamu biman jaa bialhuda min AAindihi waman takoonu lahu AAaqibatu alddari innahu la yuflihu alththalimoona", transliterationB: "Wa qaala Moosaa Rabbeee a'alamu biman jaaa'a bilhudaa min 'indihee wa man takoonu lahoo 'aaqibatud daari innahoo laa yuflihuz zaalimoon", english: "Moses said: \"My Lord knows best who it is that comes with guidance from Him and whose end will be best in the Hereafter: certain it is that the wrong-doers will not prosper", romanUrdu: "Moosa ne jawab diya “Mera Rubb us shaks ke haal se khoob waqif hai jo uski taraf se hidayat lekar aaya hai aur wahi behtar jaanta hai ke aakhri anjaam kiska accha hona hai, haqq yeh hai ke zaalim kabhi falah nahin paatey.”" },
    { number: 38, arabic: "وَقَالَ فِرْعَوْنُ يَٰٓأَيُّهَا ٱلْمَلَأُ مَا عَلِمْتُ لَكُم مِّنْ إِلَٰهٍ غَيْرِى فَأَوْقِدْ لِى يَٰهَٰمَٰنُ عَلَى ٱلطِّينِ فَٱجْعَل لِّى صَرْحًۭا لَّعَلِّىٓ أَطَّلِعُ إِلَىٰٓ إِلَٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ مِنَ ٱلْكَٰذِبِينَ", transliteration: "Waqala firAAawnu ya ayyuha almalao ma AAalimtu lakum min ilahin ghayree faawqid lee ya hamanu AAala altteeni faijAAal lee sarhan laAAallee attaliAAu ila ilahi moosa wainnee laathunnuhu mina alkathibeena", transliterationB: "Wa qaala Fir'awnu yaaa aiyuhal mala-u maa 'alimtu lakum min ilaahin ghairee fa awqid lee yaa Haamaanu 'alatteeni faj'al lee sarhal la'alleee attali'u ilaaa ilaahi Moosaa wa innee la azunnuhoo minal kaazibeen", english: "Pharaoh said: \"O Chiefs! no god do I know for you but myself: therefore, O Haman! light me a (kiln to bake bricks) out of clay, and build me a lofty palace, that I may mount up to the god of Moses: but as far as I am concerned, I think (Moses) is a liar", romanUrdu: "Aur Firoun ne kaha “Aey ehle darbaar main to apne siwa tumhare kisi khuda ko nahin jaanta. Hamaan, zara eatain (bricks) pakwa kar mere liye ek unchi imarat to banwa, shayad ke uspar chadh kar main Moosa ke khuda ko dekh sakoon, main to isey jhoota hi samajhta hoon”" },
    { number: 39, arabic: "وَٱسْتَكْبَرَ هُوَ وَجُنُودُهُۥ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَظَنُّوٓا۟ أَنَّهُمْ إِلَيْنَا لَا يُرْجَعُونَ", transliteration: "Waistakbara huwa wajunooduhu fee alardi bighayri alhaqqi wathannoo annahum ilayna la yurjaAAoona", transliterationB: "Wastakbara huwa wa junooduhoo fil ardi bighairil haqqi wa zannooo annahum ilainaa laa yurja'oon", english: "And he was arrogant and insolent in the land, beyond reason,- He and his hosts: they thought that they would not have to return to Us", romanUrdu: "Usne aur uske lashkaron ne zameen mein bagair kisi haqq ke apni badayi ka ghamand kiya aur samjhe ke unhein kabhi hamari taraf palatna nahin hai" },
    { number: 40, arabic: "فَأَخَذْنَٰهُ وَجُنُودَهُۥ فَنَبَذْنَٰهُمْ فِى ٱلْيَمِّ ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلظَّٰلِمِينَ", transliteration: "Faakhathnahu wajunoodahu fanabathnahum fee alyammi faonthur kayfa kana AAaqibatu alththalimeena", transliterationB: "Fa akhaznaahu wa junoo dahoo fanabaznaahum fil yammi fanzur kaifa kaana 'aaqibatuz zaalimeen", english: "So We seized him and his hosts, and We flung them into the sea: Now behold what was the end of those who did wrong", romanUrdu: "Aakhir-e-kaar humne usey aur uske lashkaron ko pakda aur samandar mein phenk diya, ab dekhlo ke un zaalimon ka kaisa anjaam hua" },
    { number: 41, arabic: "وَجَعَلْنَٰهُمْ أَئِمَّةًۭ يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ لَا يُنصَرُونَ", transliteration: "WajaAAalnahum aimmatan yadAAoona ila alnnari wayawma alqiyamati la yunsaroona", transliterationB: "Wa ja'alnaahum a'immatany yad'oona ilan Naari wa Yawmal Qiyaamati laa yunsaroon", english: "And we made them (but) leaders inviting to the Fire; and on the Day of Judgment no help shall they find", romanUrdu: "Humne unhein jahannum ki taraf dawat dene waley pesh-ro bana diya aur qayamat ke roz woh kahin se koi madad na paa sakenge" },
    { number: 42, arabic: "وَأَتْبَعْنَٰهُمْ فِى هَٰذِهِ ٱلدُّنْيَا لَعْنَةًۭ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ هُم مِّنَ ٱلْمَقْبُوحِينَ", transliteration: "WaatbaAAnahum fee hathihi alddunya laAAnatan wayawma alqiyamati hum mina almaqbooheena", transliterationB: "Wa atba'naahum fee haazihid dunyaa la'natanw wa Yawmal Qiyaamati hum minal maqbooheen", english: "in this world We made a curse to follow them and on the Day of Judgment they will be among the loathed (and despised)", romanUrdu: "Humne is duniya mein unke pichey laanat laga di aur qayamat ke roz woh badi qabahat (awkward predicament) mein mubtila hongey" },
    { number: 43, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ مِنۢ بَعْدِ مَآ أَهْلَكْنَا ٱلْقُرُونَ ٱلْأُولَىٰ بَصَآئِرَ لِلنَّاسِ وَهُدًۭى وَرَحْمَةًۭ لَّعَلَّهُمْ يَتَذَكَّرُونَ", transliteration: "Walaqad atayna moosa alkitaba min baAAdi ma ahlakna alquroona aloola basaira lilnnasi wahudan warahmatan laAAallahum yatathakkaroona", transliterationB: "Wa laqad aatainaa Moosal Kitaaba mim ba'di maaa ahlaknal quroonal oolaa basaaa'ira linnaasi wa hudanw wa rahmatal la'allahum yata zakkkaroon", english: "We did reveal to Moses the Book after We had destroyed the earlier generations, (to give) Insight to men, and guidance and Mercy, that they might receive admonition", romanUrdu: "Pichli nasalon ko halaak karne ke baad humne Moosa ko kitaab ata ki, logon ke liye baseeraton ka samaan(means of enlightenment) bana kar, hidayat aur rehmat bana kar, taa-ke shayad log sabaq haasil karein" },
    { number: 44, arabic: "وَمَا كُنتَ بِجَانِبِ ٱلْغَرْبِىِّ إِذْ قَضَيْنَآ إِلَىٰ مُوسَى ٱلْأَمْرَ وَمَا كُنتَ مِنَ ٱلشَّٰهِدِينَ", transliteration: "Wama kunta bijanibi algharbiyyi ith qadayna ila moosa alamra wama kunta mina alshshahideena", transliterationB: "Wa maa kunta bijaanibil gharbiyyi iz qadainaaa ilaa Moosal amra wa maa kunta minash shaahideen", english: "Thou wast not on the Western side when We decreed the Commission to Moses, nor wast thou a witness (of those events)", romanUrdu: "(Aey Muhammad) tum us waqt magrabi goshey(western side) mein maujood na thay jab humne Moosa ko yeh farmaan e shariyat ata kiya aur na tum shahideen (witnesses) mein shamil thay" },
    { number: 45, arabic: "وَلَٰكِنَّآ أَنشَأْنَا قُرُونًۭا فَتَطَاوَلَ عَلَيْهِمُ ٱلْعُمُرُ ۚ وَمَا كُنتَ ثَاوِيًۭا فِىٓ أَهْلِ مَدْيَنَ تَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِنَا وَلَٰكِنَّا كُنَّا مُرْسِلِينَ", transliteration: "Walakinna anshana quroonan fatatawala AAalayhimu alAAumuru wama kunta thawiyan fee ahli madyana tatloo AAalayhim ayatina walakinna kunna mursileena", transliterationB: "Wa laakinnaa anshaanaa quroonan fatataawala 'alaihimul 'umur; wa maa kunta saawiyan feee ahli Madyana tatloo 'alaihim Aayaatinaa wa laakinnaa kunnaa mursileen", english: "But We raised up (new) generations, and long were the ages that passed over them; but thou wast not a dweller among the people of Madyan, rehearsing Our Signs to them; but it is We Who send messengers (with inspiration)", romanUrdu: "Balke iske baad (tumhare zamane tak) hum bahut se nasalein (generations) utha chuke hain aur unpar bahut zamana guzar chuka hai. Tum ehle Madiyan ke darmiyaan bhi maujood na thay ke unko hamari aayat suna rahey hotey, Magar (us waqt ki yeh khabrein) bhejne waley hum hain" },
    { number: 46, arabic: "وَمَا كُنتَ بِجَانِبِ ٱلطُّورِ إِذْ نَادَيْنَا وَلَٰكِن رَّحْمَةًۭ مِّن رَّبِّكَ لِتُنذِرَ قَوْمًۭا مَّآ أَتَىٰهُم مِّن نَّذِيرٍۢ مِّن قَبْلِكَ لَعَلَّهُمْ يَتَذَكَّرُونَ", transliteration: "Wama kunta bijanibi alttoori ith nadayna walakin rahmatan min rabbika litunthira qawman ma atahum min natheerin min qablika laAAallahum yatathakkaroona", transliterationB: "Wa maa kunta bijaanibit Toori iz naadainaa wa laakir rahmatam mir Rabbika litunzira qawmam maaa ataahum min nazeerim min qablika la'allahum yatazakkaroon", english: "Nor wast thou at the side of (the Mountain of) Tur when we called (to Moses). Yet (art thou sent) as Mercy from thy Lord, to give warning to a people to whom no warner had come before thee: in order that they may receive admonition", romanUrdu: "Aur tum Toor ke daaman mein bhi us waqt maujood na they jab humne (Moosa ko pehli martaba) pukara tha, magar yeh tumhare Rubb ki rehmat hai (ke tumko yeh malumaat di jaa rahi hain) taa-ke tum un logon ko mutanabbeh (warn) kardo jinke paas tumse pehle koi mutanabbeh (warn) karne wala nahin aaya, shayad ke woh hosh mein aayein" },
    { number: 47, arabic: "وَلَوْلَآ أَن تُصِيبَهُم مُّصِيبَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَيَقُولُوا۟ رَبَّنَا لَوْلَآ أَرْسَلْتَ إِلَيْنَا رَسُولًۭا فَنَتَّبِعَ ءَايَٰتِكَ وَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ", transliteration: "Walawla an tuseebahum museebatun bima qaddamat aydeehim fayaqooloo rabbana lawla arsalta ilayna rasoolan fanattabiAAa ayatika wanakoona mina almumineena", transliterationB: "Wa law laaa an tuseebahum museebatum bimaa qaddamat aideehim fa yaqooloo Rabbanaa law laaa arsalta ilainaa Rasoolan fanattabi'a Aayaatika wa nakoona minal mu'mineen", english: "If (We had) not (sent thee to the Quraish),- in case a calamity should seize them for (the deeds) that their hands have sent forth, they might say: \"Our Lord! why didst Thou not sent us a messenger? We should then have followed Thy Signs and been amongst those who believe", romanUrdu: "(Aur yeh humne isliye kiya ke) kahin aisa na ho ke unke apne kiye kartooton ki badaulat koi museebat jab unpar aaye to woh kahein “aey parwardigar, tu-nay kyun na hamari taraf koi Rasool bheja ke hum teri aayaat ki pairawi karte aur ehle iman mein se hotey.”" },
    { number: 48, arabic: "فَلَمَّا جَآءَهُمُ ٱلْحَقُّ مِنْ عِندِنَا قَالُوا۟ لَوْلَآ أُوتِىَ مِثْلَ مَآ أُوتِىَ مُوسَىٰٓ ۚ أَوَلَمْ يَكْفُرُوا۟ بِمَآ أُوتِىَ مُوسَىٰ مِن قَبْلُ ۖ قَالُوا۟ سِحْرَانِ تَظَٰهَرَا وَقَالُوٓا۟ إِنَّا بِكُلٍّۢ كَٰفِرُونَ", transliteration: "Falamma jaahumu alhaqqu min AAindina qaloo lawla ootiya mithla ma ootiya moosa awalam yakfuroo bima ootiya moosa min qablu qaloo sihrani tathahara waqaloo inna bikullin kafiroona", transliterationB: "Falammaa jaaa'ahumul haqqu min 'indinaa qaaloo law laa ootiya misla maaa ootiyaa Moosaa; awalam yakfuroo bimaaa ootiya Moosaa min qablu qaaloo sihraani tazaaharaa wa qaalooo innaa bikullin kaafiroon", english: "But (now), when the Truth has come to them from Ourselves, they say, \"Why are not (Signs) sent to him, like those which were sent to Moses?\" Do they not then reject (the Signs) which were formerly sent to Moses? They say: \"Two kinds of sorcery, each assisting the other!\" And they say: \"For us, we reject all (such things)", romanUrdu: "Magar jab hamare haan se haqq unke paas aa gaya to woh kehne lagey ‘kyun na diya gaya isko wahi kuch jo Moosa ko diya gaya tha?” Kya yeh log uska inkar nahin kar chuke hain jo issey pehle Moosa ko diya gaya tha? Unhon ne kaha “dono jaadu hain jo ek dusre ki madad karte hain” aur kaha “hum kisi ko nahin maante.”" },
    { number: 49, arabic: "قُلْ فَأْتُوا۟ بِكِتَٰبٍۢ مِّنْ عِندِ ٱللَّهِ هُوَ أَهْدَىٰ مِنْهُمَآ أَتَّبِعْهُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Qul fatoo bikitabin min AAindi Allahi huwa ahda minhuma attabiAAhu in kuntum sadiqeena", transliterationB: "Qul faatoo bi Kitaabim min 'indil laahi huwa ahdaa minhu maaa attabi'hu in kuntum saadiqeen", english: "Say: \"Then bring ye a Book from Allah, which is a better guide than either of them, that I may follow it! (do), if ye are truthful", romanUrdu: "(Aey Nabi) insey kaho “accha to laao Allah ki taraf se koi kitaab jo in dono se zyada hidayat bakshne wali ho agar tum sacchey ho, main usi ki pairwi ikhtiyar karunga.”" },
    { number: 50, arabic: "فَإِن لَّمْ يَسْتَجِيبُوا۟ لَكَ فَٱعْلَمْ أَنَّمَا يَتَّبِعُونَ أَهْوَآءَهُمْ ۚ وَمَنْ أَضَلُّ مِمَّنِ ٱتَّبَعَ هَوَىٰهُ بِغَيْرِ هُدًۭى مِّنَ ٱللَّهِ ۚ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", transliteration: "Fain lam yastajeeboo laka faiAAlam annama yattabiAAoona ahwaahum waman adallu mimmani ittabaAAa hawahu bighayri hudan mina Allahi inna Allaha la yahdee alqawma alththalimeena", transliterationB: "Fa il lam yastajeeboo laka fa'lam annamaa yattabi'oona ahwaaa'ahum; w aman adallu mimmanit taba'a hawaahu bighari hudam minal laah; innal laaha laa yahdil qawmaz zaalimeen", english: "But if they hearken not to thee, know that they only follow their own lusts: and who is more astray than one who follow his own lusts, devoid of guidance from Allah? for Allah guides not people given to wrong-doing", romanUrdu: "Ab agar woh tumhara yeh mutalaba poora nahin karte to samajh lo ke dar asal yeh apni khwahishat ke pairo hain, aur us shaks se badh kar kaun gumraah hoga jo khudayi hidayat ke bagair bas apni khwahishat ki pairwi karey? Allah aise zaalimon ko hargiz hidayat nahin bakshta" },
    { number: 51, arabic: "۞ وَلَقَدْ وَصَّلْنَا لَهُمُ ٱلْقَوْلَ لَعَلَّهُمْ يَتَذَكَّرُونَ", transliteration: "Walaqad wassalna lahumu alqawla laAAallahum yatathakkaroona", transliterationB: "Wa laqad wassalnaa lahumul qawla la'allahum yatazakkaroon", english: "Now have We caused the Word to reach them themselves, in order that they may receive admonition", romanUrdu: "Aur (naseehat ki ) baat pai dar pai hum unhein pahuncha chuke hain taa-ke woh gaflat se bedaar hon" },
    { number: 52, arabic: "ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ مِن قَبْلِهِۦ هُم بِهِۦ يُؤْمِنُونَ", transliteration: "Allatheena ataynahumu alkitaba min qablihi hum bihi yuminoona", transliterationB: "Allazeena aatainaahu mul Kitaaba min qablihee hum bihee yu'minoon", english: "Those to whom We sent the Book before this,- they do believe in this (revelation)", romanUrdu: "Jin logon ko issey pehle humne kitaab di thi woh is (Quran) par iman latey hain" },
    { number: 53, arabic: "وَإِذَا يُتْلَىٰ عَلَيْهِمْ قَالُوٓا۟ ءَامَنَّا بِهِۦٓ إِنَّهُ ٱلْحَقُّ مِن رَّبِّنَآ إِنَّا كُنَّا مِن قَبْلِهِۦ مُسْلِمِينَ", transliteration: "Waitha yutla AAalayhim qaloo amanna bihi innahu alhaqqu min rabbina inna kunna min qablihi muslimeena", transliterationB: "Wa izaa yutlaa 'alaihim qaaloo aamannaa biheee innahul haqqu mir rabbinaaa innaa kunnaa min qablihee muslimeen", english: "And when it is recited to them, they say: \"We believe therein, for it is the Truth from our Lord: indeed we have been Muslims (bowing to Allah's Will) from before this", romanUrdu: "Aur jab yeh unko sunaya jata hai to woh kehte hain ke “ hum ispar iman laye, yeh waqayi haqq hai hamare Rubb ki taraf se, hum to pehle hi se Muslim hain”" },
    { number: 54, arabic: "أُو۟لَٰٓئِكَ يُؤْتَوْنَ أَجْرَهُم مَّرَّتَيْنِ بِمَا صَبَرُوا۟ وَيَدْرَءُونَ بِٱلْحَسَنَةِ ٱلسَّيِّئَةَ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ", transliteration: "Olaika yutawna ajrahum marratayni bima sabaroo wayadraoona bialhasanati alssayyiata wamimma razaqnahum yunfiqoona", transliterationB: "Ulaaa'ika yu'tawna ajrahum marratayni bimaa sabaroo wa yadra'oona bil hasanatis saiyi'ata wa mimmmaa razaq naahum yunfiqoon", english: "Twice will they be given their reward, for that they have persevered, that they avert Evil with Good, and that they spend (in charity) out of what We have given them", romanUrdu: "Yeh woh log hain jinhein unka ajar do baar diya jayega us saabit qadami ke badle jo unhon ne dikhayi. Woh burayi ko bhalayi se dafa karte hain aur jo kuch rizq humne unhein diya hai usmein se kharch karte hain" },
    { number: 55, arabic: "وَإِذَا سَمِعُوا۟ ٱللَّغْوَ أَعْرَضُوا۟ عَنْهُ وَقَالُوا۟ لَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ سَلَٰمٌ عَلَيْكُمْ لَا نَبْتَغِى ٱلْجَٰهِلِينَ", transliteration: "Waitha samiAAoo allaghwa aAAradoo AAanhu waqaloo lana aAAmaluna walakum aAAmalukum salamun AAalaykum la nabtaghee aljahileena", transliterationB: "Wa izaa sami'ul laghwa a'radoo 'anhu wa qaaloo lanaaa a'maalunaa wa lakum a'maalukum salaamun 'alaikum laa nabtaghil jaahileen", english: "And when they hear vain talk, they turn away therefrom and say: \"To us our deeds, and to you yours; peace be to you: we seek not the ignorant", romanUrdu: "Aur jab unhon ne behuda baat suni to yeh keh kar ussey kinara kash ho gaye ke “hamare aamal hamare liye aur tumhare aamal tumhare liye, tumko salaam hai, hum jaahilon ka sa tareeqa ikhtiyar karna nahin chahte.”" },
    { number: 56, arabic: "إِنَّكَ لَا تَهْدِى مَنْ أَحْبَبْتَ وَلَٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۚ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ", transliteration: "Innaka la tahdee man ahbabta walakinna Allaha yahdee man yashao wahuwa aAAlamu bialmuhtadeena", transliterationB: "Innaka laa tahdee man ahbata wa laakinna laaha yahdee mai yashaaa'; wa Huwaa'lamu bilmuhtadeen", english: "It is true thou wilt not be able to guide every one, whom thou lovest; but Allah guides those whom He will and He knows best those who receive guidance", romanUrdu: "“Aey Nabi, tum jisey chaho usey hidayat nahin de sakte, magar Allah jisey chahta hai hidayat deta hai aur woh un logon ko khoob jaanta hai jo hidayat qabool karne waley hain.”" },
    { number: 57, arabic: "وَقَالُوٓا۟ إِن نَّتَّبِعِ ٱلْهُدَىٰ مَعَكَ نُتَخَطَّفْ مِنْ أَرْضِنَآ ۚ أَوَلَمْ نُمَكِّن لَّهُمْ حَرَمًا ءَامِنًۭا يُجْبَىٰٓ إِلَيْهِ ثَمَرَٰتُ كُلِّ شَىْءٍۢ رِّزْقًۭا مِّن لَّدُنَّا وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", transliteration: "Waqaloo in nattabiAAi alhuda maAAaka nutakhattaf min ardina awalam numakkin lahum haraman aminan yujba ilayhi thamaratu kulli shayin rizqan min ladunna walakinna aktharahum la yaAAlamoona", transliterationB: "Wa qaalooo in nattabi'il hudaa ma'aka nutakhattaf min ardinaa; awalam numakkkil lahum haraman aaminany yujbaaa ilaihi samaraatu kulli shai'ir rizqam mil ladunnaa wa laakinna aksarahum laa ya'lamoon", english: "They say: \"If we were to follow the guidance with thee, we should be snatched away from our land.\" Have We not established for them a secure sanctuary, to which are brought as tribute fruits of all kinds,- a provision from Ourselves? but most of them understand not", romanUrdu: "Woh kehte hain “agar hum tumhare saath is hidayat ki pairwi ikhtiyar karlein to apni zameen se uchak liye jaayenge.” Kya yeh waqia nahin hai ke humne ek pur-aman haram(makkah) ko inke liye jaaye qiyam bana diya jiski taraf har tarah ke samaraat(provision) khinchey chaley aate hain, hamari taraf se rizq ke taur par? Magar inmein se aksar log jaante nahin hain" },
    { number: 58, arabic: "وَكَمْ أَهْلَكْنَا مِن قَرْيَةٍۭ بَطِرَتْ مَعِيشَتَهَا ۖ فَتِلْكَ مَسَٰكِنُهُمْ لَمْ تُسْكَن مِّنۢ بَعْدِهِمْ إِلَّا قَلِيلًۭا ۖ وَكُنَّا نَحْنُ ٱلْوَٰرِثِينَ", transliteration: "Wakam ahlakna min qaryatin batirat maAAeeshataha fatilka masakinuhum lam tuskan min baAAdihim illa qaleelan wakunna nahnu alwaritheena", transliterationB: "Wa kam ahlaknaa min qaryatim batirat ma'eeshatahaa fatilka masaainuhum lam tuskam mim ba'dihim illaa qaleelaa; wa kunnaa Nahnul waariseen", english: "And how many populations We destroyed, which exulted in their life (of ease and plenty)! now those habitations of theirs, after them, are deserted,- All but a (miserable) few! and We are their heirs", romanUrdu: "Aur kitni hi aisi bastiyan hum tabaah kar chuke hain jinke log apni maishat (economy) par itra gaye thay so dekhlo, woh unke maskan padey huey hain jin mein unke baad kam hi koi basa hai. Aakhir e kaar hum hi waris ho kar rahey" },
    { number: 59, arabic: "وَمَا كَانَ رَبُّكَ مُهْلِكَ ٱلْقُرَىٰ حَتَّىٰ يَبْعَثَ فِىٓ أُمِّهَا رَسُولًۭا يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِنَا ۚ وَمَا كُنَّا مُهْلِكِى ٱلْقُرَىٰٓ إِلَّا وَأَهْلُهَا ظَٰلِمُونَ", transliteration: "Wama kana rabbuka muhlika alqura hatta yabAAatha fee ommiha rasoolan yatloo AAalayhim ayatina wama kunna muhlikee alqura illa waahluha thalimoona", transliterationB: "Wa maa kaana Rabbuka muhlikal quraa hattaa yab'asa feee ummihaa Rasoolany yatloo 'alaihim aayaatina; wa maa kunnaa muhlikil quraaa illaa wa ahluhaa zaalimoon", english: "Nor was thy Lord the one to destroy a population until He had sent to its centre a messenger, rehearsing to them Our Signs; nor are We going to destroy a population except when its members practise iniquity", romanUrdu: "Aur tera Rubb bastiyon ko halaak karne wala na tha jab tak ke unke markaz mein ek Rasool na bhejh deta jo unko hamari aayat sunata, aur hum bastiyon ko halaak karne waley na they jab tak ke unke rehne waley zaalim na ho jatey" },
    { number: 60, arabic: "وَمَآ أُوتِيتُم مِّن شَىْءٍۢ فَمَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَزِينَتُهَا ۚ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ وَأَبْقَىٰٓ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Wama ooteetum min shayin famataAAu alhayati alddunya wazeenatuha wama AAinda Allahi khayrun waabqa afala taAAqiloona", transliterationB: "Wa maaa ooteetum min shai'in famataa'ul hayaatid dunyaa wa zeenatuhaa; wa maa 'indal laahi khairunw wa abqaa; afalaa ta'qiloon", english: "The (material) things which ye are given are but the conveniences of this life and the glitter thereof; but that which is with Allah is better and more enduring: will ye not then be wise", romanUrdu: "Tum logon ko jo kuch bhi diya gaya hai woh mehaz duniya ki zindagi ka samaan aur uski zeenat(adornment) hai, aur jo kuch Allah ke paas hai woh issey behtar aur baaqi tar hai. Kya tum log aqal se kaam nahin letay" },
    { number: 61, arabic: "أَفَمَن وَعَدْنَٰهُ وَعْدًا حَسَنًۭا فَهُوَ لَٰقِيهِ كَمَن مَّتَّعْنَٰهُ مَتَٰعَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ثُمَّ هُوَ يَوْمَ ٱلْقِيَٰمَةِ مِنَ ٱلْمُحْضَرِينَ", transliteration: "Afaman waAAadnahu waAAdan hasanan fahuwa laqeehi kaman mattaAAnahu mataAAa alhayati alddunya thumma huwa yawma alqiyamati mina almuhdareena", transliterationB: "Afamanw wa'adnaahu wa'dan hasanan fahuwa laaqeehi kamam matta'naahu mataa'al hayaatid dunyaa summa huwa Yawmal Qiyaamati minal muhdareen", english: "Are (these two) alike?- one to whom We have made a goodly promise, and who is going to reach its (fulfilment), and one to whom We have given the good things of this life, but who, on the Day of Judgment, is to be among those brought up (for punishment)", romanUrdu: "Bhala woh shaks jissey humne accha wada kiya ho, aur woh usey panay wala ho kabhi us shaks ki tarah ho sakta hai jisey humne sirf hayat-e-duniya ka sar-o-samaan de diya ho, aur phir woh qayamat ke roz saza ke liye pesh kiya janey wala ho" },
    { number: 62, arabic: "وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ", transliteration: "Wayawma yunadeehim fayaqoolu ayna shurakaiya allatheena kuntum tazAAumoona", transliterationB: "Wa Yawma yunaadeehim fa-yaqoolu aina shurakaaa 'iyal lazeena kuntum taz'umoon", english: "That Day (Allah) will call to them, and say \"Where are my 'partners'?- whom ye imagined (to be such)", romanUrdu: "Aur (bhool na jayein yeh log) us din ko jabke woh inko pukarega aur puchega “kahan hai mere woh shareek jinka tum gumaan rakhte thay?”" },
    { number: 63, arabic: "قَالَ ٱلَّذِينَ حَقَّ عَلَيْهِمُ ٱلْقَوْلُ رَبَّنَا هَٰٓؤُلَآءِ ٱلَّذِينَ أَغْوَيْنَآ أَغْوَيْنَٰهُمْ كَمَا غَوَيْنَا ۖ تَبَرَّأْنَآ إِلَيْكَ ۖ مَا كَانُوٓا۟ إِيَّانَا يَعْبُدُونَ", transliteration: "Qala allatheena haqqa AAalayhimu alqawlu rabbana haolai allatheena aghwayna aghwaynahum kama ghawayna tabarrana ilayka ma kanoo iyyana yaAAbudoona", transliterationB: "Qaalal lazeena haqqa 'alaihimul qawlu Rabbanaa haaa'ulaaa'il lazeena aghwainaa aghwainaahu kamaa ghawainaa tabarraanaaa ilaika maa kaanoo iyyaanaa ya'budoon", english: "Those against whom the charge will be proved, will say: \"Our Lord! These are the ones whom we led astray: we led them astray, as we were astray ourselves: we free ourselves (from them) in Thy presence: it was not us they worshipped", romanUrdu: "Yeh qaul jinpar chaspan hoga woh kahenge “Aey hamare Rubb, beshak yahi log hain jinko humne gumraah kiya tha, inhein humne usi tarah gumraah kiya jaise hum khud gumraah huey. Hum aap ke saamne baraat(disassociation) ka izhar karte hain. Yeh hamari to bandagi nahin karte thay”" },
    { number: 64, arabic: "وَقِيلَ ٱدْعُوا۟ شُرَكَآءَكُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُوا۟ لَهُمْ وَرَأَوُا۟ ٱلْعَذَابَ ۚ لَوْ أَنَّهُمْ كَانُوا۟ يَهْتَدُونَ", transliteration: "Waqeela odAAoo shurakaakum fadaAAawhum falam yastajeeboo lahum waraawoo alAAathaba law annahum kanoo yahtadoona", transliterationB: "Wa qeelad 'oo shurakaaa'akum fada'awhum falam yastajeeboo lahum wa ra awul 'azaab; law annahum kaanoo yahtadoon", english: "It will be said (to them): \"Call upon your 'partners' (for help)\": they will call upon them, but they will not listen to them; and they will see the Penalty (before them); (how they will wish) 'if only they had been open to guidance", romanUrdu: "Phir insey kaha jayega ke pukaro ab apne thehraye huey shareekon ko. Yeh unhein pukarenge magar woh inko koi jawab na dengey aur yeh log azaab dekh lenge. Kaash yeh hidayat ikhtiyar karne waley hotey" },
    { number: 65, arabic: "وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ مَاذَآ أَجَبْتُمُ ٱلْمُرْسَلِينَ", transliteration: "Wayawma yunadeehim fayaqoolu matha ajabtumu almursaleena", transliterationB: "Wa Yawma yunaadeehim fa yaqoolu maazaaa ajabtumul mursaleen", english: "That Day (Allah) will call to them, and say: \"What was the answer ye gave to the messengers", romanUrdu: "Aur (faramosh na karein yeh log) woh din jabke woh inko pukarega aur puchega ke “Jo Rasool bheje gaye thay unhein tumne kya jawab diya tha?”" },
    { number: 66, arabic: "فَعَمِيَتْ عَلَيْهِمُ ٱلْأَنۢبَآءُ يَوْمَئِذٍۢ فَهُمْ لَا يَتَسَآءَلُونَ", transliteration: "FaAAamiyat AAalayhimu alanbao yawmaithin fahum la yatasaaloona", transliterationB: "Fa'amiyat 'alaihimul ambaaa'u Yawma'izin fahum laa yatasaaa'aloon", english: "Then the (whole) story that Day will seem obscure to them (like light to the blind) and they will not be able (even) to question each other", romanUrdu: "Us waqt koi jawab inko na soojhega aur na yeh aapas mein ek dusre se puch hi sakenge" },
    { number: 67, arabic: "فَأَمَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا فَعَسَىٰٓ أَن يَكُونَ مِنَ ٱلْمُفْلِحِينَ", transliteration: "Faamma man taba waamana waAAamila salihan faAAasa an yakoona mina almufliheena", transliterationB: "Fa ammaa man taaba wa aamana wa 'amila saalihan fa'asaaa ai yakoona minal mufliheen", english: "But any that (in this life) had repented, believed, and worked righteousness, will have hopes to be among those who achieve salvation", romanUrdu: "Albatta jisne aaj toubah karli aur iman le aaya aur neik amal kiye wahi yeh tawakko(expect) kar sakta hai ke wahan falaah paaney walon mein se hoga" },
    { number: 68, arabic: "وَرَبُّكَ يَخْلُقُ مَا يَشَآءُ وَيَخْتَارُ ۗ مَا كَانَ لَهُمُ ٱلْخِيَرَةُ ۚ سُبْحَٰنَ ٱللَّهِ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ", transliteration: "Warabbuka yakhluqu ma yashao wayakhtaru ma kana lahumu alkhiyaratu subhana Allahi wataAAala AAamma yushrikoona", transliterationB: "Wa Rabbuka yakhuluqu maa yashaaa'u wa yakhtaar; maa kaana lahumul khiyarah; Subhannal laahi wa Ta'aalaa 'ammmaa yushrikoon", english: "Thy Lord does create and choose as He pleases: no choice have they (in the matter): Glory to Allah! and far is He above the partners they ascribe (to Him)", romanUrdu: "Tera Rubb paida karta hai jo kuch chahta hai. Aur (woh khud hi apne kaam ke liye jisey chahta hai) muntakhab(choose) kar leta hai. Yeh intekhab in logon ke karne ka kaam nahin hai, Allah paak hai aur bahut baala-tarr hai us shirk se jo yeh log karte hain" },
    { number: 69, arabic: "وَرَبُّكَ يَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ", transliteration: "Warabbuka yaAAlamu ma tukinnu sudooruhum wama yuAAlinoona", transliterationB: "Wa Rabbuka ya'lamu maa tukinnu sudooruhum wa maa yu'linoon", english: "And thy Lord knows all that their hearts conceal and all that they reveal", romanUrdu: "Tera Rubb jaanta hai jo kuch yeh dilon mein chupaye huey hain aur jo kuch yeh zaahir karte hain" },
    { number: 70, arabic: "وَهُوَ ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۖ لَهُ ٱلْحَمْدُ فِى ٱلْأُولَىٰ وَٱلْءَاخِرَةِ ۖ وَلَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Wahuwa Allahu la ilaha illa huwa lahu alhamdu fee aloola waalakhirati walahu alhukmu wailayhi turjaAAoona", transliterationB: "Wa Huwal laahu laaa ilaaha illaa Huwa lahul hamdu fil oolaa wal Aakhirati wa lahul hukmu wa ilaihi turja'oon", english: "And He is Allah: There is no god but He. To Him be praise, at the first and at the last: for Him is the Command, and to Him shall ye (all) be brought back", romanUrdu: "Wahi ek Allah hai jiske siwa koi ibadat ka mustahiq nahin. Usi ke liye hamd hai duniya mein bhi aur aakhirat mein bhi, Farma rawayi usi ki hai aur usi ki taraf tum sab palataye janey waley ho" },
    { number: 71, arabic: "قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلَّيْلَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَنْ إِلَٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِضِيَآءٍ ۖ أَفَلَا تَسْمَعُونَ", transliteration: "Qul araaytum in jaAAala Allahu AAalaykumu allayla sarmadan ila yawmi alqiyamati man ilahun ghayru Allahi yateekum bidiyain afala tasmaAAoona", transliterationB: "Qul ara'aitum in ja'alal laahu 'alaikumul laila sarmadan ilaa Yawmil Qiyaamati man ilaahun ghairul laahi yaa teekum bidiyaaa'in afalaa tasma'oon", english: "Say: See ye? If Allah were to make the night perpetual over you to the Day of Judgment, what god is there other than Allah, who can give you enlightenment? Will ye not then hearken", romanUrdu: "Aey Nabi, insey kaho kabhi tum logon ne gaur kiya ke agar Allah qayamat tak tumpar hamesha ke liye raat taari karde to Allah ke siwa woh kaunsa mabood hai jo tumhein roshni laa dey? Kya tum sunte nahin ho" },
    { number: 72, arabic: "قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلنَّهَارَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَنْ إِلَٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِلَيْلٍۢ تَسْكُنُونَ فِيهِ ۖ أَفَلَا تُبْصِرُونَ", transliteration: "Qul araaytum in jaAAala Allahu AAalaykumu alnnahara sarmadan ila yawmi alqiyamati man ilahun ghayru Allahi yateekum bilaylin taskunoona feehi afala tubsiroona", transliterationB: "Qul ara'aitum in ja'alal laahu 'alaikumun nahaara sarmadan ilaa Yawmil Qiyaamati man ilaahun ghairul laahi yaateekum bilailin taskunoona feehi afalaa tubsiroon", english: "Say: See ye? If Allah were to make the day perpetual over you to the Day of Judgment, what god is there other than Allah, who can give you a night in which ye can rest? Will ye not then see", romanUrdu: "Insey pucho, kabhi tumne socha ke agar Allah qayamat tak tumpar hamesha ke liye din taari karde to Allah ke siwa woh kaunsa maabood hai jo tumhein raat laa dey taa-ke tum usmein sukoon haasil kar sako? Kya tumko soojhta nahin" },
    { number: 73, arabic: "وَمِن رَّحْمَتِهِۦ جَعَلَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ لِتَسْكُنُوا۟ فِيهِ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Wamin rahmatihi jaAAala lakumu allayla waalnnahara litaskunoo feehi walitabtaghoo min fadlihi walaAAallakum tashkuroona", transliterationB: "Wa mir rahmatihee ja'ala lakumul laila wannahaara litaskunoo feehi wa litabtaghoo min fadlihee wa la'allakum tashkuroon", english: "It is out of His Mercy that He has made for you Night and Day,- that ye may rest therein, and that ye may seek of his Grace;- and in order that ye may be grateful", romanUrdu: "Yeh usi ki rehmat hai ke usne tumhare liye raat aur din banaye taa-ke tum (raat mein) sukoon haasil karo aur (din ko) apne Rubb ka fazal talash karo. Shayad ke tum shukar guzar bano" },
    { number: 74, arabic: "وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ", transliteration: "Wayawma yunadeehim fayaqoolu ayna shurakaiya allatheena kuntum tazAAumoona", transliterationB: "Wa Yawma yunaadeehim fa yaqoolu aina shurakaaa'iyal lazeena kuntum tazz'umoon", english: "The Day that He will call on them, He will say: \"Where are my 'partners'? whom ye imagined (to be such)", romanUrdu: "(Yaad rakhein yeh log) woh din jabke woh inhein pukarega phir puchega “kahan hai mere woh shareek jinka tum gumaan rakhte thay?”" },
    { number: 75, arabic: "وَنَزَعْنَا مِن كُلِّ أُمَّةٍۢ شَهِيدًۭا فَقُلْنَا هَاتُوا۟ بُرْهَٰنَكُمْ فَعَلِمُوٓا۟ أَنَّ ٱلْحَقَّ لِلَّهِ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "WanazaAAna min kulli ommatin shaheedan faqulna hatoo burhanakum faAAalimoo anna alhaqqa lillahi wadalla AAanhum ma kanoo yaftaroona", transliterationB: "Wa naza'naa min kulli ummatin shaheedan faqulnaa haatoo burhaanakum fa'alimooo annal haqqa lillaahi wa dalla 'anhum maa kaanoo yaftaroon", english: "And from each people shall We draw a witness, and We shall say: \"Produce your Proof\": then shall they know that the Truth is in Allah (alone), and the (lies) which they invented will leave them in lurch", romanUrdu: "Aur hum har ummat mein se ek gawah nikal layenge phir kahenge ke “lao ab apni daleel”. Us waqt inhein maloom ho jayega ke haqq Allah ki taraf hai, aur gum (vanish) ho jayenge inke woh saarey jhoot jo inhon ne ghadh rakkhe thay" },
    { number: 76, arabic: "۞ إِنَّ قَٰرُونَ كَانَ مِن قَوْمِ مُوسَىٰ فَبَغَىٰ عَلَيْهِمْ ۖ وَءَاتَيْنَٰهُ مِنَ ٱلْكُنُوزِ مَآ إِنَّ مَفَاتِحَهُۥ لَتَنُوٓأُ بِٱلْعُصْبَةِ أُو۟لِى ٱلْقُوَّةِ إِذْ قَالَ لَهُۥ قَوْمُهُۥ لَا تَفْرَحْ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْفَرِحِينَ", transliteration: "Inna qaroona kana min qawmi moosa fabagha AAalayhim waataynahu mina alkunoozi ma inna mafatihahu latanooo bialAAusbati olee alquwwati ith qala lahu qawmuhu la tafrah inna Allaha la yuhibbu alfariheena", transliterationB: "Inna Qaaroona kaana min qawmi Moosaa fabaghaaa 'alaihim wa aatainaahu minal kunoozi maaa inna mafaati hahoo latanooo'u bil'usbati ulil quwwati iz qaala lahoo qawmuhoo laa tafrah innal laahaa laa yuhibbul fariheen", english: "Qarun was doubtless, of the people of Moses; but he acted insolently towards them: such were the treasures We had bestowed on him that their very keys would have been a burden to a body of strong men, behold, his people said to him: \"Exult not, for Allah loveth not those who exult (in riches)", romanUrdu: "Yeh ek waqia hai ke Qaroon Moosa ki qaum ka ek shaks tha, phir woh apni qaum ke khilaf sarkash ho gaya aur humne usko itney khazane (treasures) de rakkhe thay ke unki kunjiyan (keys) taqatwar aadmiyon ki ek jamaat mushkil se utha sakti thi. Ek dafa jab uski qaum ke logon ne ussey kaha “ phoolna (itrana /exult) jaa, Allah phoolne(itrane) walon ko pasand nahin karta" },
    { number: 77, arabic: "وَٱبْتَغِ فِيمَآ ءَاتَىٰكَ ٱللَّهُ ٱلدَّارَ ٱلْءَاخِرَةَ ۖ وَلَا تَنسَ نَصِيبَكَ مِنَ ٱلدُّنْيَا ۖ وَأَحْسِن كَمَآ أَحْسَنَ ٱللَّهُ إِلَيْكَ ۖ وَلَا تَبْغِ ٱلْفَسَادَ فِى ٱلْأَرْضِ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُفْسِدِينَ", transliteration: "Waibtaghi feema ataka Allahu alddara alakhirata wala tansa naseebaka mina alddunya waahsin kama ahsana Allahu ilayka wala tabghi alfasada fee alardi inna Allaha la yuhibbu almufsideena", transliterationB: "Wabtaghi feemaaa aataakal laahud Daaral Aakhirata wa laa tansa naseebaka minad dunyaa wa ahsin kamaaa ahsanal laahu ilaika wa laa tabghil fasaada fil ardi innal laaha laa yuhibbul mufsideen", english: "But seek, with the (wealth) which Allah has bestowed on thee, the Home of the Hereafter, nor forget thy portion in this world: but do thou good, as Allah has been good to thee, and seek not (occasions for) mischief in the land: for Allah loves not those who do mischief", romanUrdu: "Jo maal Allah ne tujhey diya hai ussey aakhirat ka ghar banane ki fikar kar, aur duniya mein se bhi apna hissa faramosh na kar. Ehsan kar jis tarah Allah ne tere saath ehsan kiya hai, aur zameen mein fasaad barpa karne ki koshish na kar, Allah mufsidon (fasaad karne waalon) ko pasand nahin karta.”" },
    { number: 78, arabic: "قَالَ إِنَّمَآ أُوتِيتُهُۥ عَلَىٰ عِلْمٍ عِندِىٓ ۚ أَوَلَمْ يَعْلَمْ أَنَّ ٱللَّهَ قَدْ أَهْلَكَ مِن قَبْلِهِۦ مِنَ ٱلْقُرُونِ مَنْ هُوَ أَشَدُّ مِنْهُ قُوَّةًۭ وَأَكْثَرُ جَمْعًۭا ۚ وَلَا يُسْـَٔلُ عَن ذُنُوبِهِمُ ٱلْمُجْرِمُونَ", transliteration: "Qala innama ooteetuhu AAala AAilmin AAindee awalam yaAAlam anna Allaha qad ahlaka min qablihi mina alqurooni man huwa ashaddu minhu quwwatan waaktharu jamAAan wala yusalu AAan thunoobihimu almujrimoona", transliterationB: "Qaala innamaaa ootee tuhoo 'alaa 'ilmin 'indeee; awalam ya'lam annal laaha qad ahlaka min qablihee minal qurooni man huwa ashaddu minhu quwwatanw wa aksaru jam'aa; wa laa yus'alu 'an zunoobihimul mujrimoon", english: "He said: \"This has been given to me because of a certain knowledge which I have.\" Did he not know that Allah had destroyed, before him, (whole) generations,- which were superior to him in strength and greater in the amount (of riches) they had collected? but the wicked are not called (immediately) to account for their sins", romanUrdu: "To usne kaha “Yeh sab kuch to mujhey us ilm ki bina par diya gaya hai jo mujhko haasil hai”. Kya usko yeh ilm na tha ke Allah ussey pehle bahut se aisey logon ko halaak kar chuka hai jo ussey zyada quwwat aur jamiyat rakhte thay? Mujrim se to unke gunaah nahin puchey jatey" },
    { number: 79, arabic: "فَخَرَجَ عَلَىٰ قَوْمِهِۦ فِى زِينَتِهِۦ ۖ قَالَ ٱلَّذِينَ يُرِيدُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا يَٰلَيْتَ لَنَا مِثْلَ مَآ أُوتِىَ قَٰرُونُ إِنَّهُۥ لَذُو حَظٍّ عَظِيمٍۢ", transliteration: "Fakharaja AAala qawmihi fee zeenatihi qala allatheena yureedoona alhayata alddunya ya layta lana mithla ma ootiya qaroonu innahu lathoo haththin AAatheemin", transliterationB: "Fakharaja 'alaa qawmihee fee zeenatih; qaalal lazeena yureedoonal hayaatad dunyaa yaalaita lanaa misla maaa ootiya Qaaroonu innahoo lazoo hazzin 'azeem", english: "So he went forth among his people in the (pride of his wordly) glitter. Said those whose aim is the Life of this World: \"Oh! that we had the like of what Qarun has got! for he is truly a lord of mighty good fortune", romanUrdu: "Ek roz woh apni qaum ke saamne apne puray thaat mein nikla. Jo log hayat e duniya ke taalib thay woh usey dekh kar kehne lagey “kaash humein bhi wahi kuch milta jo Qaroon ko diya gaya hai, yeh to bada naseebe wala hai.”" },
    { number: 80, arabic: "وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَيْلَكُمْ ثَوَابُ ٱللَّهِ خَيْرٌۭ لِّمَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا وَلَا يُلَقَّىٰهَآ إِلَّا ٱلصَّٰبِرُونَ", transliteration: "Waqala allatheena ootoo alAAilma waylakum thawabu Allahi khayrun liman amana waAAamila salihan wala yulaqqaha illa alssabiroona", transliterationB: "Wa qaalal lazeena ootul 'ilma wailakum sawaabul laahi khairul liman aamana wa 'amila saalihaa; wa laa yulaq qaahaaa illas saabiroon", english: "But those who had been granted (true) knowledge said: \"Alas for you! The reward of Allah (in the Hereafter) is best for those who believe and work righteousness: but this none shall attain, save those who steadfastly persevere (in good)", romanUrdu: "Magar jo log ilm rakhne waley thay woh kehne lagey “Afsos tumhare haal par, Allah ka sawaab behtar hai us shaks ke liye jo iman laye aur neik amal karey, aur yeh daulat nahin milti magar sabr karne waalon ko.”" },
    { number: 81, arabic: "فَخَسَفْنَا بِهِۦ وَبِدَارِهِ ٱلْأَرْضَ فَمَا كَانَ لَهُۥ مِن فِئَةٍۢ يَنصُرُونَهُۥ مِن دُونِ ٱللَّهِ وَمَا كَانَ مِنَ ٱلْمُنتَصِرِينَ", transliteration: "Fakhasafna bihi wabidarihi alarda fama kana lahu min fiatin yansuroonahu min dooni Allahi wama kana mina almuntasireena", transliterationB: "Fakhasafnaa bihee wa bidaarihil arda famaa kaana laho min fi'atiny yansuroo nahoo min doonil laahi wa maa kaana minal muntasireen", english: "Then We caused the earth to swallow up him and his house; and he had not (the least little) party to help him against Allah, nor could he defend himself", romanUrdu: "Aakhir-e-kaar humne usey aur uske ghar ko zameen mein dhansa diya, phir koi uske haamiyon(supporters) ka giroh na tha jo Allah ke muqabley mein uski madad ko aata, aur na woh khud apni madad aap kar saka" },
    { number: 82, arabic: "وَأَصْبَحَ ٱلَّذِينَ تَمَنَّوْا۟ مَكَانَهُۥ بِٱلْأَمْسِ يَقُولُونَ وَيْكَأَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ ۖ لَوْلَآ أَن مَّنَّ ٱللَّهُ عَلَيْنَا لَخَسَفَ بِنَا ۖ وَيْكَأَنَّهُۥ لَا يُفْلِحُ ٱلْكَٰفِرُونَ", transliteration: "Waasbaha allatheena tamannaw makanahu bialamsi yaqooloona waykaanna Allaha yabsutu alrrizqa liman yashao min AAibadihi wayaqdiru lawla an manna Allahu AAalayna lakhasafa bina waykaannahu la yuflihu alkafiroona", transliterationB: "Wa asbahal lazeena tamannaw makaanahoo bil amsi yaqooloona waika annal laaha yabsutur rizqa limany ya shaaa'u min 'ibaadihee wa yaqdiru law laaa am mannal laahu 'alainaa lakhasafa binaa waika annahoo laa yuflihul kaafiroon", english: "And those who had envied his position the day before began to say on the morrow: \"Ah! it is indeed Allah Who enlarges the provision or restricts it, to any of His servants He pleases! had it not been that Allah was gracious to us, He could have caused the earth to swallow us up! Ah! those who reject Allah will assuredly never prosper", romanUrdu: "Ab wahi log jo kal uski manzilat ki tamanna kar rahey thay kehne lagey “afsos, hum bhool gaye thay ke Allah apne bandon mein se jiska rizq chahta hai kushada karta hai aur jisey chahta hai napa-tula deta hai.Agar Allah ne humpar ehsan na kiya hota to humein bhi zameen mein dhansa deta. Afsos humko yaad na raha ke kafir falaah nahin paya karte.”" },
    { number: 83, arabic: "تِلْكَ ٱلدَّارُ ٱلْءَاخِرَةُ نَجْعَلُهَا لِلَّذِينَ لَا يُرِيدُونَ عُلُوًّۭا فِى ٱلْأَرْضِ وَلَا فَسَادًۭا ۚ وَٱلْعَٰقِبَةُ لِلْمُتَّقِينَ", transliteration: "Tilka alddaru alakhiratu najAAaluha lillatheena la yureedoona AAuluwwan fee alardi wala fasadan waalAAaqibatu lilmuttaqeena", transliterationB: "Tilkad Daarul Aakhiratu naj'aluhaa lillazeena laa yureedoona 'uluwwan fil ardi wa laa fasaadaa; wal 'aaqibatu lilmuttaqeen", english: "That Home of the Hereafter We shall give to those who intend not high-handedness or mischief on earth: and the end is (best) for the righteous", romanUrdu: "Woh aakhirat ka ghar to hum un logon ke liye makhsoos kar dengey jo zameen mein apni badayi nahin chahte aur na fasaad karna chahte hain. Aur anjaam ki bhalayi muttaqin hi ke liye hai" },
    { number: 84, arabic: "مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌۭ مِّنْهَا ۖ وَمَن جَآءَ بِٱلسَّيِّئَةِ فَلَا يُجْزَى ٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Man jaa bialhasanati falahu khayrun minha waman jaa bialssayyiati fala yujza allatheena AAamiloo alssayyiati illa ma kanoo yaAAmaloona", transliterationB: "Man jaaa'a bilhasanati falahoo khairum minhaa wa man jaaa'a bissaiyi'ati falaa yujzal lazeena 'amilus saiyiaati illaa maa kaanoo ya'maloon", english: "If any does good, the reward to him is better than his deed; but if any does evil, the doers of evil are only punished (to the extent) of their deeds", romanUrdu: "Jo koi bhalayi lekar aayega uske liye ussey behtar bhalayi hai, aur jo burayi lekar aaye to buraiyan karne walon ko waisa hi badla milega jaise amal woh karte thay" },
    { number: 85, arabic: "إِنَّ ٱلَّذِى فَرَضَ عَلَيْكَ ٱلْقُرْءَانَ لَرَآدُّكَ إِلَىٰ مَعَادٍۢ ۚ قُل رَّبِّىٓ أَعْلَمُ مَن جَآءَ بِٱلْهُدَىٰ وَمَنْ هُوَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Inna allathee farada AAalayka alqurana laradduka ila maAAadin qul rabbee aAAlamu man jaa bialhuda waman huwa fee dalalin mubeenin", transliterationB: "Innal azee farada 'alaikal Qur-aana laraaadduka ilaa ma'aad; qur Rabbeee a'lamu man jjaaa'a bil hudaa wa man huwa fee dalaalim mubeen", english: "Verily He Who ordained the Qur'an for thee, will bring thee back to the Place of Return. Say: \"My Lord knows best who it is that brings true guidance, and who is in manifest error", romanUrdu: "Aey Nabi, yaqeen jaano ke jisne yeh Quran tumpar farz kiya hai woh tumhein ek behtareen anjaam ko pahunchane wala hai. In logon se kehdo ke “Mera Rubb khoob jaanta hai ke hidayat lekar kaun aaya aur khuli gumraahi mein kaun mubtala hai.”" },
    { number: 86, arabic: "وَمَا كُنتَ تَرْجُوٓا۟ أَن يُلْقَىٰٓ إِلَيْكَ ٱلْكِتَٰبُ إِلَّا رَحْمَةًۭ مِّن رَّبِّكَ ۖ فَلَا تَكُونَنَّ ظَهِيرًۭا لِّلْكَٰفِرِينَ", transliteration: "Wama kunta tarjoo an yulqa ilayka alkitabu illa rahmatan min rabbika fala takoonanna thaheeran lilkafireena", transliterationB: "Wa maa kunta tarjooo ai yulqaaa ilaikal Kitaabu illaa rahmatam mir Rabbika falaa takoonanna zaheeral lilkaafireen", english: "And thou hadst not expected that the Book would be sent to thee except as a Mercy from thy Lord: Therefore lend not thou support in any way to those who reject (Allah's Message)", romanUrdu: "Tum is baat ke hargiz umeedwar na thay ke tumpar kitaab nazil ki jayegi. Yeh to mehaz tumhare Rubb ki meharbani se (tumpar nazil hui hai), pas tum kafiron ke madadgaar na bano" },
    { number: 87, arabic: "وَلَا يَصُدُّنَّكَ عَنْ ءَايَٰتِ ٱللَّهِ بَعْدَ إِذْ أُنزِلَتْ إِلَيْكَ ۖ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ وَلَا تَكُونَنَّ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Wala yasuddunnaka AAan ayati Allahi baAAda ith onzilat ilayka waodAAu ila rabbika wala takoonanna mina almushrikeena", transliterationB: "Wa laa yasuddunnaka 'an Aayaatil laahi ba'da iz unzilat ilaika wad'u ilaa Rabbika wa laa takonanna minal mushrikeen", english: "And let nothing keep thee back from the Signs of Allah after they have been revealed to thee: and invite (men) to thy Lord, and be not of the company of those who join gods with Allah", romanUrdu: "Aur aisa kabhi na honay paye ke Allah ki aayat jab tumpar nazil hoon to kuffar tumhein unsey baaz rakhein. Apne Rubb ki taraf dawat do aur hargiz mushrikon mein shamil na ho" },
    { number: 88, arabic: "وَلَا تَدْعُ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ ۘ لَآ إِلَٰهَ إِلَّا هُوَ ۚ كُلُّ شَىْءٍ هَالِكٌ إِلَّا وَجْهَهُۥ ۚ لَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Wala tadAAu maAAa Allahi ilahan akhara la ilaha illa huwa kullu shayin halikun illa wajhahu lahu alhukmu wailayhi turjaAAoona", transliterationB: "Wa laa tad'u ma'al laahi ilaahan aakhar; laaa ilaaha illaa Hoo; kullu shai'in haalikun illaa Wajhah; lahul hukkmu wa ilaihi turja'oon", english: "And call not, besides Allah, on another god. There is no god but He. Everything (that exists) will perish except His own Face. To Him belongs the Command, and to Him will ye (all) be brought back", romanUrdu: "Aur Allah ke saath kisi dusre mabood ko na pukaro. Uske siwa koi mabood nahin hai. Har cheez halaak honay wali hai siwaye uski zaat ke. Farman rawayi usi ki hai aur usi ki taraf tum sab paltaye janey waley ho" }
  ]
};
